query:
SELECT platform, COUNT(*) as sessions, COALESCE(SUM(creditsUsed),0) as credits_used 
FROM ai_sessions 
GROUP BY platform;

SELECT s.planId, s.status, COUNT(*) as count 
FROM subscriptions s 
GROUP BY s.planId, s.status;

SELECT type, COUNT(*) as count, COALESCE(SUM(ABS(amount)),0) as total_amount 
FROM credit_transactions 
GROUP BY type;

